#include <stdio.h>
#include <stdint.h>

static inline long long ceil_div(long long a, long long b) {
    return (a + b - 1) / b;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        long long X;
        scanf("%d %lld", &N, &X);
        long long sum = 0;
        long long maxCeil = 0;
        for (int i = 0; i < N; ++i) {
            long long a;
            scanf("%lld", &a);
            sum += a;
            long long cur = ceil_div(X, a);
            if (cur > maxCeil) maxCeil = cur;
        }
        __int128 totalWork = (__int128)X * N;
        long long totalCeil = (long long)((totalWork + sum - 1) / sum);
        long long ans = N;
        if (maxCeil > ans) ans = maxCeil;
        if (totalCeil > ans) ans = totalCeil;
        printf("%lld\n", ans);
    }
    return 0;
}

