import java.io.*;
import java.util.*;

public class Main {
    private static long ceilDiv(long a, long b) {
        return (a + b - 1) / b;
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long X = fs.nextLong();
            long sum = 0;
            long maxCeil = 0;
            for (int i = 0; i < N; ++i) {
                long a = fs.nextLong();
                sum += a;
                maxCeil = Math.max(maxCeil, ceilDiv(X, a));
            }
            // total work = X * N, may overflow long, use double check with BigInteger or use division safely
            java.math.BigInteger total = java.math.BigInteger.valueOf(X).multiply(java.math.BigInteger.valueOf(N));
            long totalCeil = total.add(java.math.BigInteger.valueOf(sum - 1)).divide(java.math.BigInteger.valueOf(sum)).longValue();
            long ans = Math.max(N, Math.max(maxCeil, totalCeil));
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c;
            while ((c = readByte()) <= ' ') {
                if (c == -1) return -1;
            }
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

